test_cases.python_test_script:
def test_tc_gw_rev_001_message_present(can_bus):
    msgs = collect_messages(can_bus, GW_REVERSE_GEAR_ID, 2)
    assert msgs

def test_tc_gw_rev_002_inactive_state(can_bus):
    msgs = collect_messages(can_bus, GW_REVERSE_GEAR_ID, 2)
    assert msgs
    for msg in msgs:
        assert decode_reverse_active(msg) == 0

def test_tc_gw_rev_003_active_state(can_bus):
    msgs = collect_messages(can_bus, GW_REVERSE_GEAR_ID, 2)
    assert msgs
    for msg in msgs:
        assert decode_reverse_active(msg) == 1

def test_tc_gw_rev_004_deactivation(can_bus):
    msgs = collect_messages(can_bus, GW_REVERSE_GEAR_ID, 2)
    assert msgs
    for msg in msgs:
        assert decode_reverse_active(msg) == 0

def test_tc_gw_rev_005_no_unintended_toggle(can_bus):
    msgs = collect_messages(can_bus, GW_REVERSE_GEAR_ID, 3)
    assert msgs
    first = decode_reverse_active(msgs[0])
    for msg in msgs:
        assert decode_reverse_active(msg) == first

def test_tc_gw_rev_006_dlc_check(can_bus):
    msgs = collect_messages(can_bus, GW_REVERSE_GEAR_ID, 2)
    assert msgs
    for msg in msgs:
        assert msg.dlc == GW_REVERSE_GEAR_DLC
